import React, { useContext } from "react";
import { Link, graphql } from "gatsby";
import Layout, { LangContext } from "../components/Layout";
import SEO from "../components/SEO";
import DataPanel from "../components/DataPanel";
import { pickLangNodes, langSlug } from "../utils/i18n";

const OpportunitiesPage = ({ data }) => {
  const { lang } = useContext(LangContext);
  const daily = pickLangNodes(data.daily.nodes, lang);
  const onDemand = pickLangNodes(data.onDemand.nodes, lang);
  const latestDaily = daily[0];

  const l = (vi, en) => lang === "vi" ? vi : en;
  const title = l("🎯 Cơ hội & Đầu tư", "🎯 Plays & Opportunities");
  const subtitle = l("Đánh giá cơ hội cho nhà phát triển độc lập", "Scored solo developer opportunities");
  const latestLabel = l("🛠️ Phân tích mới nhất", "🛠️ Latest Analysis");
  const viewFull = l("Xem báo cáo đầy đủ →", "View full report →");
  const onDemandLabel = l("🎯 Phân tích theo yêu cầu", "🎯 On-Demand Deep Dives");
  const dailyLabel = l("📋 Báo cáo Khả thi Hàng ngày", "📋 Daily Feasibility Reports");

  return (
    <Layout>
      <div className="page-header">
        <h1>{title}</h1>
        <p className="page-subtitle">{subtitle}</p>
      </div>

      <div className="opp-grid">
        {latestDaily && (
          <DataPanel title={`${latestLabel} — ${latestDaily.fields?.date || ""}`}>
            <div className="report-content markdown-body">
              <div dangerouslySetInnerHTML={{ __html: latestDaily.html || `<p>${l("Chưa có báo cáo.", "No report available.")}</p>` }} />
            </div>
            {latestDaily.fields?.slug && (
              <Link to={langSlug(latestDaily.fields.slug, lang)} className="view-all" style={{ marginTop: "12px", display: "inline-block" }}>
                {viewFull}
              </Link>
            )}
          </DataPanel>
        )}

        <div className="side-panels">
          {onDemand.length > 0 && (
            <DataPanel title={onDemandLabel}>
              <div className="report-list">
                {onDemand.map((report) => (
                  <Link key={report.id} to={langSlug(report.fields?.slug || "/", lang)} className="report-list-item">
                    <span className="report-date">{report.fields?.date || "—"}</span>
                    <span className="report-title">
                      {report.fields?.inferredTitle || "Analysis"}
                    </span>
                  </Link>
                ))}
              </div>
            </DataPanel>
          )}

          <DataPanel title={dailyLabel}>
            <div className="report-list">
              {daily.slice(0, 10).map((report) => (
                <Link key={report.id} to={langSlug(report.fields?.slug || "/", lang)} className="report-list-item">
                  <span className="report-date">{report.fields?.date || "—"}</span>
                  <span className="report-title">
                    {report.fields?.inferredTitle || "Product Engineer Report"}
                  </span>
                </Link>
              ))}
            </div>
          </DataPanel>
        </div>
      </div>
    </Layout>
  );
};

export default OpportunitiesPage;

export const Head = ({ location }) => {
  const lang = location?.pathname?.startsWith("/en") ? "en" : "vi";
  return (
    <SEO
      title={lang === "vi" ? "Cơ hội & Đầu tư — Bobbie Intelligence" : "Plays & Opportunities — Bobbie Intelligence"}
      description={lang === "vi"
        ? "Đánh giá cơ hội cho solo developer: khả thi AI SaaS, chiến lược kiếm tiền và phân tích thị trường."
        : "Scored solo developer opportunities: AI SaaS feasibility, market entry plays, and monetization strategies."}
      path="/opportunities/"
      lang={lang}
    />
  );
};

export const query = graphql`
  query OpportunitiesPage {
    daily: allMarkdownRemark(
      filter: { fields: { category: { eq: "product-engineer" }, reportType: { eq: "daily" } } }
      sort: { fields: { date: DESC } }
      limit: 20
    ) {
      nodes {
        id
        html
        fields {
          slug
          date
          inferredTitle
          lang
          baseName
        }
      }
    }
    onDemand: allMarkdownRemark(
      filter: { fields: { category: { eq: "product-engineer" }, reportType: { eq: "on-demand" } } }
      sort: { fields: { date: DESC } }
    ) {
      nodes {
        id
        fields {
          slug
          date
          inferredTitle
          lang
          baseName
        }
      }
    }
  }
`;
